#nullable enable // autogenerated

using MVZ2.GameContent.Effects;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine.Damages;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.Projectiles
{
    [AutoEntityBehaviourDefinition(VanillaProjectileNames.lockedChestTrash)]
    public class LockedChestTrash : EntityBehaviourDefinition
    {
        public LockedChestTrash(string nsp, string name) : base(nsp, name)
        {
        }
        public override void PostDeath(Entity entity, DeathInfo deathInfo)
        {
            base.PostDeath(entity, deathInfo);
            if (entity.WillRemoveOnDeath(deathInfo))
                return;
            entity.Level.ShakeScreen(1, 0, 1);
            entity.PlaySound(VanillaSoundID.smallExplosion);
            Explosion.Spawn(entity, entity.Position, 0);
        }
        public static int RandomVariant(RandomGenerator rng)
        {
            return rng.Next(MAX_VARIANT);
        }
        public const int MAX_VARIANT = 20;
    }
}
